SELECT r.id AS id, r.reporter_id AS reporterId, r.post_id AS postId, r.reason_type AS reasonType, r.reason_desc AS reasonDesc, r.status AS status, r.admin_remark AS adminRemark, r.handled_by AS handledBy, r.created_at AS createdAt, r.handled_at AS handledAt, u.nickname AS reporterNickname, p.title AS postTitle, p.description AS postDescription, p.status AS postStatus, a.username AS handledAdminName FROM post_report r LEFT JOIN user u ON u.id = r.reporter_id LEFT JOIN post p ON p.id = r.post_id LEFT JOIN admin a ON a.id = r.handled_by
r.status = #{status}
ORDER BY r.created_at DESC, r.id DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM post_report r


        r.status = #{status}

SELECT COUNT(1)
FROM post_report
WHERE post_id = #{postId}
  AND reporter_id = #{userId}
  AND status = 0
